<script setup>
import { ref, watch, defineProps, defineEmits } from "vue";
import { useI18n } from "vue-i18n";

const { locale } = useI18n();

const props = defineProps({
  data: {
    type: Array,
    required: true,
  },
  active: {
    type: [String, Number],
    default: null,
  },
});
const emit = defineEmits(["changeDistrict"]);

const hoveredRegion = ref(null);

const getName = (id) => {
  // 1. Qashqadaryo tumanlarining nomlari
  const districtNames = {
    1710220: { uz: "Qamashi tumani", ru: "Камашинский район", en: "Qamashi District" },
    1710233: { uz: "Mirishkor tumani", ru: "Миришкорский район", en: "Mirishkor District" },
    1710234: { uz: "Muborak tumani", ru: "Мубарекский район", en: "Muborak District" },
    1710235: { uz: "Nishon tumani", ru: "Нишанский район", en: "Nishon District" },
    1710229: { uz: "Koson tumani", ru: "Касанский район", en: "Koson District" },
    1710240: { uz: "Ko'kdala tumani", ru: "Кукдалинский район", en: "Kokdala District" },
    1710242: { uz: "Chiroqchi tumani", ru: "Чиракчинский район", en: "Chiroqchi District" },
    1710237: { uz: "Kasbi tumani", ru: "Касбийский район", en: "Kasbi District" },
    1710401: { uz: "Qarshi shahri", ru: "город Карши", en: "Qarshi City" },
    1710224: { uz: "Qarshi tumani", ru: "Каршинский район", en: "Qarshi District" },
    1710232: { uz: "Kitob tumani", ru: "Китабский район", en: "Kitob District" },
    1710405: { uz: "Shahrisabz shahri", ru: "город Шахрисабз", en: "Shahrisabz City" },
    1710245: { uz: "Shahrisabz tumani", ru: "Шахрисабзский район", en: "Shahrisabz District" },
    1710207: { uz: "G'uzor tumani", ru: "Гузарский район", en: "Guzar District" },
    1710212: { uz: "Dehqonobod tumani", ru: "Дехканабадский район", en: "Dekhkanabad District" },
    1710250: { uz: "Yakkabog' tumani", ru: "Яккабагский район", en: "Yakkabag District" }
  };

  // 2. API dan kelgan ma'lumotni tekshirish
  const district = props.data.find((district) => district.id == id);
  
  if (district) {
    // API dan nom kelgan bo'lsa
    if (district.district_name && district.district_name[locale.value]) {
      return district.district_name[locale.value];
    }
    // Yoki boshqa nom field'lari
    if (district.name && typeof district.name === 'object') {
      return district.name[locale.value];
    }
    if (district.name && typeof district.name === 'string') {
      return district.name;
    }
  }

  // 3. Qo'lda belgilangan nomlardan olish
  if (districtNames[id] && districtNames[id][locale.value]) {
    return districtNames[id][locale.value];
  }

  // 4. Fallback
  return `Tuman ${id}`;
};

const getPathStyle = (id) => {
  const district = props.data.find((district) => district.id == id);

  let className = "";

  if (district) {
    if (district.status == "good") {
      className += "text-ratingGood";
    } else if (district.status == "bad") {
      className += "text-ratingBad";
    } else {
      className += "text-ratingNormal";
    }
  }

  className += props.active == id ? " active" : "";

  if (hoveredRegion.value == id || props.active == id) {
    className += " active-path";
  } else if (hoveredRegion.value != null && props.active != id) {
    className += " inactive-path";
  }

  return className.trim();
};

watch(
  () => props.active,
  () => (hoveredRegion.value = null),
  { immediate: true }
);
</script>
